@implementation WBEventManager

+ (WBEventManager*)defaultManager {
    static WBEventManager* instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBEventManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        _queue = dispatch_queue_create("__eventqueue", NULL);
        _eventList = [[NSMutableArray alloc] init];
        _lastReportTime = 0;
        _vappUsedTimeInSecond = 0;
        _enabled = FALSE;
        dispatch_async([self queue], ^{
            [self processEventList];
            [self vappUsageRecord];
        });
        [self load];
    }
    return self;
}

- (void)load {
    NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
    if (![NSFileManager.defaultManager fileExistsAtPath:filePath]) {
        return;
    }
    NSError *error = nil;
    NSData *data = [NSData dataWithContentsOfFile:filePath options:0 error:&error];
    if (error || !data) {
        return;
    }
    id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
    if (error || ![json isKindOfClass:[NSArray class]]) {
        return;
    }
    NSArray *entries = (NSArray *)json;
    NSMutableArray<WBEvent *> *events = [NSMutableArray arrayWithCapacity:entries.count];
    for (id item in entries) {
        if (![item isKindOfClass:[NSDictionary class]]) {
            continue;
        }
        NSDictionary *entry = (NSDictionary *)item;
        NSNumber *typeNum = entry[@"n"];
        NSNumber *timeNum = entry[@"t"];
        id paramsObj = entry[@"d"];
        if (!typeNum || ![typeNum isKindOfClass:[NSNumber class]]) {
            continue;
        }
        WBEvent *event = [[WBEvent alloc] initWithType:typeNum.integerValue data:[paramsObj isKindOfClass:[NSDictionary class]] ? paramsObj : nil];
        if ([timeNum isKindOfClass:[NSNumber class]]) {
            event.time = timeNum.doubleValue;
        }
        event.status = eventStatusAwaitReport;
        event.urgent = NO;
        [events addObject:event];
    }
    if (events.count > 0) {
        dispatch_async([self queue], ^{
            [[self eventList] addObjectsFromArray:events];
        });
    }
    [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
}

- (void)save {
    __block NSArray<WBEvent *> *snapshot = nil;
    dispatch_sync([self queue], ^{
        snapshot = [[self eventList] copy];
    });
    NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
    if (snapshot.count == 0) {
        if ([NSFileManager.defaultManager fileExistsAtPath:filePath]) {
            [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
        }
        return;
    }
    NSMutableArray *entries = [NSMutableArray arrayWithCapacity:snapshot.count];
    for (WBEvent *event in snapshot) {
        NSMutableDictionary *dict = [NSMutableDictionary dictionary];
        dict[@"t"] = @(event.time);
        dict[@"n"] = @(event.type);
        if (event.params) {
            dict[@"d"] = event.params;
        }
        [entries addObject:dict];
    }
    NSError *error = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:entries options:0 error:&error];
    if (error || !data) {
        return;
    }
    NSURL *fileURL = [NSURL fileURLWithPath:filePath];
    BOOL ok = [data writeToURL:fileURL options:NSDataWritingAtomic error:&error];
    if (!ok) {
        NSLog(@"EventManager save error:%@", error.localizedDescription);
        error = nil;
        ok = [data writeToURL:fileURL options:NSDataWritingAtomic error:&error];
        if (!ok) {
            NSLog(@"EventManager save retry failed:%@", error.localizedDescription);
        }
    }
}

- (void)saveAsync {
    dispatch_async([self queue], ^{
        NSArray<WBEvent *> *snapshot = [[self eventList] copy];
        NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
        if (snapshot.count == 0) {
            if ([NSFileManager.defaultManager fileExistsAtPath:filePath]) {
                [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
            }
            return;
        }
        NSMutableArray *entries = [NSMutableArray arrayWithCapacity:snapshot.count];
        for (WBEvent *event in snapshot) {
            NSMutableDictionary *dict = [NSMutableDictionary dictionary];
            dict[@"t"] = @(event.time);
            dict[@"n"] = @(event.type);
            if (event.params) {
                dict[@"d"] = event.params;
            }
            [entries addObject:dict];
        }
        NSError *error = nil;
        NSData *data = [NSJSONSerialization dataWithJSONObject:entries options:0 error:&error];
        if (error || !data) {
            return;
        }
        NSURL *fileURL = [NSURL fileURLWithPath:filePath];
        BOOL ok = [data writeToURL:fileURL options:NSDataWritingAtomic error:&error];
        if (!ok) {
            NSLog(@"EventManager save error:%@", error.localizedDescription);
            error = nil;
            ok = [data writeToURL:fileURL options:NSDataWritingAtomic error:&error];
            if (!ok) {
                NSLog(@"EventManager save retry failed:%@", error.localizedDescription);
            }
        }
    });
}

- (uint32_t)heartbeatInterval {
    if (WBSettingManager.sharedManager.HeartBeatRate) {
        return (uint32_t)WBSettingManager.sharedManager.HeartBeatRate;
    }
    return 15;
}

- (uint32_t)reportInterval {
    if (WBSettingManager.sharedManager.LogRate) {
        return (uint32_t)WBSettingManager.sharedManager.LogRate;
    }
    return 5;
}

- (void)vappUsageRecord {
    //    NSLog(@"timer");
    _appUsedTimeInSecond += 1;

    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    NSDate *dateFromAbsoluteNow = [NSDate dateWithTimeIntervalSinceReferenceDate:now];
    NSDate *delta = floor(dateFromAbsoluteNow - _lastUsageCheckpointTime);
    if (delta > 0) {
        _appUsedTimeInSecond += delta;
    }

    if (vapp_is_running()) {
        _vappUsedTimeInSecond += 1;
    }
    if (_vappUsedTimeInSecond >= self.heartbeatInterval || _appUsedTimeInSecond >= self.heartbeatInterval) {
        [self doHeartBeatWithUsageReport];
    }
    dispatch_after(dispatch_time_delay(1), [self queue], ^{
        [self vappUsageRecord];
    });
}

- (void)doHeartBeatWithUsageReport {
    dispatch_async([self queue], ^{
        NSMutableDictionary *dataDict = [@{
            @"v" : @(self.vappUsedTimeInSecond),
            @"a" : @(self.appUsedTimeInSecond)
        } mutableCopy];

        if ([WBVAppManager sharedManager].runningVApp.vid != 0) {
            dataDict[@"i"] = @([WBVAppManager sharedManager].runningVApp.vid);
        }

        [WBEventManager addEventWithType:eventTypeAppHeartBeat data:dataDict];
        self.vappUsedTimeInSecond = 0;
        self.appUsedTimeInSecond = 0;
    });

    // do event action request
    dispatch_async(dispatch_get_main_queue(), ^{
        if (WBAppManager.sharedManager.isActive) {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInForeground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInForeground defaultHandler:nil];
            }
        } else {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInBackground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInBackground defaultHandler:nil];
            }
        }
    });
}

