#import "WBUtility.h"
#import "WBABBridge.h"
#import <CommonCrypto/CommonDigest.h>


@implementation WBUtility

+ (NSString *)getCodeNameSaltedCrc32Hash:(NSString *)key {
    return [[ABBridge_GetAppCodeName() stringByAppendingPathComponent:key] crc32String];
}

+ (NSString *)getCodeNameSaltedSha1Hash:(NSString *)key {
    return [[ABBridge_GetAppCodeName() stringByAppendingPathComponent:key] sha1String];
}

+ (NSString *)convertUTC2Local:(NSString *)utc {
    NSDateFormatter *dateFormatter = [[NSDateFormatter alloc] init];
    [dateFormatter setDateFormat:@"yyyy-MM-dd'T'HH:mm:ss.SSSSSS'Z'"];
    [dateFormatter setTimeZone:[NSTimeZone timeZoneWithAbbreviation:@"UTC"]];
    [dateFormatter setLocale:[NSLocale localeWithLocaleIdentifier:@"zh_CN"]];
    NSDate *date = [dateFormatter dateFromString:utc];

    // change to a readable time format and change to local time zone
    [dateFormatter setDateFormat:@"yyyy-MM-dd HH:mm:ss"];
    [dateFormatter setTimeZone:[NSTimeZone localTimeZone]];
    return [dateFormatter stringFromDate:date];
}

+ (void)calculateSHA1ForFolder:(NSString *)folderPath
         includeSubdirectories:(BOOL)includeSubdirectories
                    completion:(void(^)(NSString *sha1, NSError *error))completion {
    // 在后台队列执行计算，避免阻塞主线程
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        NSFileManager *fileManager = [NSFileManager defaultManager];
        // 1. 检查文件夹是否存在
        BOOL isDirectory;
        BOOL exists = [fileManager fileExistsAtPath:folderPath isDirectory:&isDirectory];
        if (!exists || !isDirectory) {
            NSError *error = [NSError errorWithDomain:@"FolderSHA1Calculator"
                                                 code:404
                                             userInfo:@{NSLocalizedDescriptionKey: @"文件夹不存在"}];
            dispatch_async(dispatch_get_main_queue(), ^{
                completion(nil, error);
            });
            return;
        }

        // 2. 获取文件夹内容
        NSArray *contents = [self getFolderContents:folderPath
                              includeSubdirectories:includeSubdirectories
                                        fileManager:fileManager];

        // 3. 按文件名排序，确保结果一致性
        NSArray *sortedContents = [contents sortedArrayUsingSelector:@selector(compare:)];

        // 4. 计算总体 SHA1
        CC_SHA1_CTX sha1Context;
        CC_SHA1_Init(&sha1Context);

        NSError *calculationError = nil;
        for (NSString *filePath in sortedContents) {
            if (![self updateSHA1Context:&sha1Context withFile:filePath error:&calculationError]) {
                break;
            }
        }

        unsigned char digest[CC_SHA1_DIGEST_LENGTH];
        CC_SHA1_Final(digest, &sha1Context);
        NSString *sha1 = [self hexStringFromDigest:digest length:CC_SHA1_DIGEST_LENGTH];

        // 5. 返回结果
        dispatch_async(dispatch_get_main_queue(), ^{
            if (calculationError) {
                completion(nil, calculationError);
            } else {
                completion(sha1, nil);
            }
        });
    });
}

/// 获取文件夹内所有文件路径
+ (NSArray *)getFolderContents:(NSString *)folderPath
         includeSubdirectories:(BOOL)includeSubdirectories
                   fileManager:(NSFileManager *)fileManager {
    NSMutableArray *allFiles = [NSMutableArray array];

    NSURL *folderURL = [NSURL fileURLWithPath:folderPath];
    NSArray *keys = @[NSURLIsDirectoryKey, NSURLIsRegularFileKey];

    NSDirectoryEnumerator *enumerator = [fileManager enumeratorAtURL:folderURL
                                          includingPropertiesForKeys:keys
                                                             options:NSDirectoryEnumerationSkipsHiddenFiles
                                                        errorHandler:^BOOL(NSURL *url, NSError *error) {
        NSLog(@"遍历文件夹错误: %@", error);
        return YES; // 继续遍历
    }];

    for (NSURL *fileURL in enumerator) {
        NSError *error;
        NSNumber *isDirectory;
        NSNumber *isRegularFile;

        if (![fileURL getResourceValue:&isDirectory forKey:NSURLIsDirectoryKey error:&error] ||
            ![fileURL getResourceValue:&isRegularFile forKey:NSURLIsRegularFileKey error:&error]) {
            continue;
        }

        // 如果是文件，添加到列表
        if ([isRegularFile boolValue]) {
            [allFiles addObject:fileURL.path];
        }

        // 如果不需要包含子目录，停止遍历子目录
        if (!includeSubdirectories && [isDirectory boolValue]) {
            [enumerator skipDescendants];
        }
    }

    return [allFiles copy];
}

/// 用文件内容更新 SHA1 上下文
+ (BOOL)updateSHA1Context:(CC_SHA1_CTX *)context
                 withFile:(NSString *)filePath
                    error:(NSError **)error {
    NSFileHandle *fileHandle = [NSFileHandle fileHandleForReadingAtPath:filePath];
    if (!fileHandle) {
        if (error) {
            *error = [NSError errorWithDomain:@"FolderSHA1Calculator"
                                         code:500
                                     userInfo:@{NSLocalizedDescriptionKey: [NSString stringWithFormat:@"无法读取文件: %@", filePath]}];
        }
        return NO;
    }

    @try {
        // 首先包含文件名（确保文件重命名会影响最终结果）
        NSData *fileNameData = [[filePath lastPathComponent] dataUsingEncoding:NSUTF8StringEncoding];
        CC_SHA1_Update(context, fileNameData.bytes, (CC_LONG)fileNameData.length);

        // 然后包含文件内容
        while (YES) {
            @autoreleasepool {
                NSData *chunk = [fileHandle readDataOfLength:512 * 1024];
                if (chunk.length == 0) {
                    break;
                }
                CC_SHA1_Update(context, chunk.bytes, (CC_LONG)chunk.length);
            }
        }

        [fileHandle closeFile];
        return YES;

    } @catch (NSException *exception) {
        [fileHandle closeFile];
        if (error) {
            *error = [NSError errorWithDomain:@"FolderSHA1Calculator"
                                         code:501
                                     userInfo:@{NSLocalizedDescriptionKey: [NSString stringWithFormat:@"读取文件时出错: %@", exception.reason]}];
        }
        return NO;
    }
}

/// 将二进制摘要转换为十六进制字符串
+ (NSString *)hexStringFromDigest:(unsigned char *)digest length:(int)length {
    NSMutableString *hashString = [NSMutableString stringWithCapacity:length * 2];
    for (int i = 0; i < length; i++) {
        [hashString appendFormat:@"%02x", digest[i]];
    }
    return [hashString copy];
}


@end

